#include <stdio.h>
#include <stdbool.h>
#include <string.h>

#define MAX_PROCESSES 5
#define MAX_RESOURCES 3

typedef struct {
 int available[MAX_RESOURCES];
 int max[MAX_PROCESSES][MAX_RESOURCES];
 int allocation[MAX_PROCESSES][MAX_RESOURCES];
 int need[MAX_PROCESSES][MAX_RESOURCES];
 int num_processes;
 int num_resources;
} Banker;

// Initialize the banker system
void init_banker(Banker *b, int available[], int max[][MAX_RESOURCES], 
 int allocation[][MAX_RESOURCES], int n, int m) {
 b->num_processes = n;
 b->num_resources = m;

 // Copy available
 for (int j = 0; j < m; j++) {
 b->available[j] = available[j];
 }

 // Copy max and allocation, calculate need
 for (int i = 0; i < n; i++) {
 for (int j = 0; j < m; j++) {
 b->max[i][j] = max[i][j];
 b->allocation[i][j] = allocation[i][j];
 b->need[i][j] = max[i][j] - allocation[i][j];
 }
 }
}

// Safety Algorithm - returns true if safe, false otherwise
// Also returns safe sequence via parameter
bool safety_check(Banker *b, int safe_sequence[]) {
 int work[MAX_RESOURCES];
 bool finish[MAX_PROCESSES];

 // Step 1: Initialize work and finish
 for (int j = 0; j < b->num_resources; j++) {
 work[j] = b->available[j];
 }
 for (int i = 0; i < b->num_processes; i++) {
 finish[i] = false;
 }

 int seq_index = 0;

 // Step 2: Find processes that can complete
 while (1) {
 bool found = false;
 for (int i = 0; i < b->num_processes; i++) {
 if (!finish[i]) {
 // Check if Need[i] <= Work
 bool can_finish = true;
 for (int j = 0; j < b->num_resources; j++) {
 if (b->need[i][j] > work[j]) {
 can_finish = false;
 break;
 }
 }

 if (can_finish) {
 // Simulate process completion
 for (int j = 0; j < b->num_resources; j++) {
 work[j] += b->allocation[i][j];
 }
 finish[i] = true;
 safe_sequence[seq_index++] = i;
 found = true;
 }
 }
 }

 if (!found) break;
 }

 // Step 3: Check if all processes can finish
 for (int i = 0; i < b->num_processes; i++) {
 if (!finish[i]) {
 return false; // Unsafe state
 }
 }

 return true; // Safe state
}

// Resource Request Algorithm
// Returns true if request granted, false otherwise
bool request_resources(Banker *b, int process_id, int request[]) {
 // Step 1: Check if request exceeds maximum claim
 for (int j = 0; j < b->num_resources; j++) {
 if (request[j] > b->need[process_id][j]) {
 printf("Error: Process P%d exceeded maximum claim\n", process_id);
 return false;
 }
 }

 // Step 2: Check if request can be satisfied
 for (int j = 0; j < b->num_resources; j++) {
 if (request[j] > b->available[j]) {
 printf("Process P%d must wait - resources unavailable\n", process_id);
 return false;
 }
 }

 // Save current state for potential rollback
 int saved_available[MAX_RESOURCES];
 int saved_allocation[MAX_RESOURCES];
 int saved_need[MAX_RESOURCES];

 for (int j = 0; j < b->num_resources; j++) {
 saved_available[j] = b->available[j];
 saved_allocation[j] = b->allocation[process_id][j];
 saved_need[j] = b->need[process_id][j];
 }

 // Step 3: Tentatively allocate
 for (int j = 0; j < b->num_resources; j++) {
 b->available[j] -= request[j];
 b->allocation[process_id][j] += request[j];
 b->need[process_id][j] -= request[j];
 }

 // Step 4: Run safety check
 int safe_sequence[MAX_PROCESSES];
 if (safety_check(b, safe_sequence)) {
 printf("Request GRANTED - Safe sequence: ");
 for (int i = 0; i < b->num_processes; i++) {
 printf("P%d ", safe_sequence[i]);
 }
 printf("\n");
 return true;
 } else {
 // Rollback
 for (int j = 0; j < b->num_resources; j++) {
 b->available[j] = saved_available[j];
 b->allocation[process_id][j] = saved_allocation[j];
 b->need[process_id][j] = saved_need[j];
 }
 printf("Request DENIED - Would lead to unsafe state\n");
 return false;
 }
}

// Print current state
void print_state(Banker *b) {
 printf("\n=== Current State ===\n");
 printf("Available: [");
 for (int j = 0; j < b->num_resources; j++) {
 printf("%d%s", b->available[j], j < b->num_resources - 1 ? ", " : "");
 }
 printf("]\n");

 printf("\nProcess Status:\n");
 printf("P#\tAllocation\tMax\tNeed\n");
 for (int i = 0; i < b->num_processes; i++) {
 printf("P%d\t[", i);
 for (int j = 0; j < b->num_resources; j++) {
 printf("%d%s", b->allocation[i][j], j < b->num_resources - 1 ? "," : "");
 }
 printf("]\t[");
 for (int j = 0; j < b->num_resources; j++) {
 printf("%d%s", b->max[i][j], j < b->num_resources - 1 ? "," : "");
 }
 printf("]\t[");
 for (int j = 0; j < b->num_resources; j++) {
 printf("%d%s", b->need[i][j], j < b->num_resources - 1 ? "," : "");
 }
 printf("]\n");
 }
}

int main() {
 // System: 5 processes, 3 resource types: A(10), B(5), C(7)
 int available[] = {3, 3, 2};

 int max[MAX_PROCESSES][MAX_RESOURCES] = {
 {7, 5, 3}, // P0
 {3, 2, 2}, // P1
 {9, 0, 2}, // P2
 {2, 2, 2}, // P3
 {4, 3, 3} // P4
 };

 int allocation[MAX_PROCESSES][MAX_RESOURCES] = {
 {0, 1, 0}, // P0
 {2, 0, 0}, // P1
 {3, 0, 2}, // P2
 {2, 1, 1}, // P3
 {0, 0, 2} // P4
 };

 Banker banker;
 init_banker(&banker, available, max, allocation, 5, 3);

 printf("======================================\n");
 printf("Banker's Algorithm - Deadlock Avoidance\n");
 printf("======================================\n");

 print_state(&banker);

 // Check initial safety
 int safe_sequence[MAX_PROCESSES];
 bool is_safe = safety_check(&banker, safe_sequence);

 printf("\n=== Initial Safety Check ===\n");
 printf("System is %s\n", is_safe ? "SAFE" : "UNSAFE");
 if (is_safe) {
 printf("Safe sequence: ");
 for (int i = 0; i < banker.num_processes; i++) {
 printf("P%d ", safe_sequence[i]);
 }
 printf("\n");
 }

 // Demonstrate P1 requesting (1, 0, 2)
 printf("\n=== Resource Request Demo ===\n");
 printf("Process P1 requests [1, 0, 2]\n");
 int request[] = {1, 0, 2};
 bool granted = request_resources(&banker, 1, request);

 if (granted) {
 printf("\nUpdated state after granting request:\n");
 printf("Available: [%d, %d, %d]\n", 
 banker.available[0], banker.available[1], banker.available[2]);
 printf("P1 Allocation: [%d, %d, %d]\n",
 banker.allocation[1][0], banker.allocation[1][1], banker.allocation[1][2]);
 printf("P1 Need: [%d, %d, %d]\n",
 banker.need[1][0], banker.need[1][1], banker.need[1][2]);
 }

 return 0;
}
